#include <stdio.h>
int main() {
    int N;
    scanf("%d", &N);
    int roads[N][4];
    for (int i = 0; i < N; i++) {
        scanf("%d %d %d %d", &roads[i][0], &roads[i][1], &roads[i][2], &roads[i][3]);
    }
    int trafficLights[N] = {0};
    int totalTrafficLights = 0;
    for (int i = 0; i < N; i++) {
        for (int j = i + 1; j < N; j++) {
            if ((roads[i][0] == roads[i][2] && roads[j][1] == roads[j][3] && roads[i][0] >= roads[j][0] && roads[i][0] <= roads[j][2] && roads[j][1] >= roads[i][1] && roads[j][1] <= roads[i][3]) ||
                (roads[j][0] == roads[j][2] && roads[i][1] == roads[i][3] && roads[j][0] >= roads[i][0] && roads[j][0] <= roads[i][2] && roads[i][1] >= roads[j][1] && roads[i][1] <= roads[j][3])) {
                trafficLights[i]++;
                trafficLights[j]++;
                totalTrafficLights++;
            }
        }
    }
    printf("%d\n", totalTrafficLights);
    for (int i = 0; i < N; i++) {
        printf("%d ", trafficLights[i]);
    }
    return 0;
}

