const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const N = parseInt(input[idx++]);
const roads = [];
for (let i = 0; i < N; i++) {
    roads.push(input[idx++].split(' ').map(x => parseInt(x)));
}
const trafficLights = new Array(N).fill(0);
let totalTrafficLights = 0;
for (let i = 0; i < N; i++) {
    for (let j = i + 1; j < N; j++) {
        if ((roads[i][0] == roads[i][2] && roads[j][1] == roads[j][3] && roads[i][0] >= roads[j][0] && roads[i][0] <= roads[j][2] && roads[j][1] >= roads[i][1] && roads[j][1] <= roads[i][3]) ||
